1	// GSD Extension — Complexity Classifier
2	// Classifies unit complexity for dynamic model routing.
3	// Pure heuristics + adaptive learning — no LLM calls. Sub-millisecond classification.
4	import { existsSync, readFileSync } from "node:fs";
5	import { join } from "node:path";
6	import { gsdRoot } from "./paths.js";
7	import { getAdaptiveTierAdjustment } from "./routing-history.js";
8	import { parseUnitId } from "./unit-id.js";
9	// ─── Unit Type → Default Tier Mapping ────────────────────────────────────────
10	const UNIT_TYPE_TIERS = {
11	    // Tier 1 — Light: structured summaries, completion, UAT
12	    "complete-slice": "light",
13	    "run-uat": "light",
14	    // Tier 2 — Standard: research, routine planning, discussion
15	    "discuss-milestone": "standard",
16	    "research-milestone": "standard",
17	    "research-slice": "standard",
18	    "plan-milestone": "standard",
19	    "plan-slice": "standard",
20	    // Tier 3 — Heavy: execution, replanning (requires deep reasoning)
21	    "execute-task": "standard", // default standard, upgraded by metadata
22	    "replan-slice": "heavy",
23	    "reassess-roadmap": "heavy",
24	};
25	// ─── Public API ─────────────────────────────────────────────────────────────
26	/**
27	 * Classify unit complexity to determine which model tier to use.
28	 *
29	 * @param unitType    The type of unit being dispatched
30	 * @param unitId      The unit ID (e.g. "M001/S01/T01")
31	 * @param basePath    Project base path (for reading task plans)
32	 * @param budgetPct   Current budget usage as fraction (0.0-1.0+), or undefined if no budget
33	 * @param metadata    Optional pre-parsed task metadata
34	 */
35	export function classifyUnitComplexity(unitType, unitId, basePath, budgetPct, metadata) {
36	    // Hook units default to light
37	    if (unitType.startsWith("hook/")) {
38	        const result = { tier: "light", reason: "hook unit", downgraded: false };
39	        return applyBudgetPressure(result, budgetPct);
40	    }
41	    // Start with the default tier for this unit type
42	    let tier = UNIT_TYPE_TIERS[unitType] ?? "standard";
43	    let reason = `unit type: ${unitType}`;
44	    // For execute-task, analyze task metadata for complexity signals
45	    if (unitType === "execute-task") {
46	        const taskAnalysis = analyzeTaskComplexity(unitId, basePath, metadata);
47	        tier = taskAnalysis.tier;
48	        reason = taskAnalysis.reason;
49	    }
50	    // For plan-slice, check if the slice has many tasks (complex planning)
51	    if (unitType === "plan-slice" || unitType === "plan-milestone") {
52	        const planAnalysis = analyzePlanComplexity(unitId, basePath);
53	        if (planAnalysis) {
54	            tier = planAnalysis.tier;
55	            reason = planAnalysis.reason;
56	        }
57	    }
58	    // Adaptive learning: check if history suggests bumping the tier
59	    const tags = metadata?.tags ?? extractTaskMetadata(unitId, basePath).tags;
60	    const adaptiveAdjustment = getAdaptiveTierAdjustment(unitType, tier, tags);
61	    if (adaptiveAdjustment && tierOrdinal(adaptiveAdjustment) > tierOrdinal(tier)) {
62	        reason = `${reason} (adaptive: high failure rate at ${tier})`;
63	        tier = adaptiveAdjustment;
64	    }
65	    const result = { tier, reason, downgraded: false };
66	    return applyBudgetPressure(result, budgetPct);
67	}
68	/**
69	 * Get a short label for the tier (for dashboard display).
70	 */
71	export function tierLabel(tier) {
72	    switch (tier) {
73	        case "light": return "L";
74	        case "standard": return "S";
75	        case "heavy": return "H";
76	    }
77	}
78	/**
79	 * Get the tier ordering value (for comparison).
80	 */
81	export function tierOrdinal(tier) {
82	    switch (tier) {
83	        case "light": return 0;
84	        case "standard": return 1;
85	        case "heavy": return 2;
86	    }
87	}
88	function analyzeTaskComplexity(unitId, basePath, metadata) {
89	    // Try to read task plan for complexity signals
90	    const meta = metadata ?? extractTaskMetadata(unitId, basePath);
91	    // Heavy signals
92	    if (meta.dependencyCount && meta.dependencyCount >= 3) {
93	        return { tier: "heavy", reason: `${meta.dependencyCount} dependencies` };
94	    }
95	    if (meta.fileCount && meta.fileCount >= 6) {
96	        return { tier: "heavy", reason: `${meta.fileCount} files to modify` };
97	    }
98	    if (meta.estimatedLines && meta.estimatedLines >= 500) {
99	        return { tier: "heavy", reason: `~${meta.estimatedLines} lines estimated` };
100	    }
101	    // Heavy signals from complexity keywords (Phase 4)
102	    if (meta.complexityKeywords && meta.complexityKeywords.length >= 2) {
103	        return { tier: "heavy", reason: `complex: ${meta.complexityKeywords.join(", ")}` };
104	    }
105	    if (meta.codeBlockCount && meta.codeBlockCount >= 5) {
106	        return { tier: "heavy", reason: `${meta.codeBlockCount} code blocks in plan` };
107	    }
108	    // Standard signals from single complexity keyword
109	    if (meta.complexityKeywords && meta.complexityKeywords.length === 1) {
110	        return { tier: "standard", reason: `${meta.complexityKeywords[0]} task` };
111	    }
112	    // Light signals (simple tasks)
113	    if (meta.tags?.some(t => /^(docs?|readme|comment|config|typo|rename)$/i.test(t))) {
114	        return { tier: "light", reason: `simple task: ${meta.tags.join(", ")}` };
115	    }
116	    if (meta.fileCount !== undefined && meta.fileCount <= 1 && !meta.isNewFile) {
117	        return { tier: "light", reason: "single file modification" };
118	    }
119	    // Standard by default
120	    return { tier: "standard", reason: "standard execution task" };
121	}
122	function analyzePlanComplexity(unitId, basePath) {
123	    // Check if this is a milestone-level plan (more complex) vs single slice
124	    const { milestone: mid, slice: sid } = parseUnitId(unitId);
125	    if (!sid) {
126	        // Milestone-level planning is always at least standard
127	        return { tier: "standard", reason: "milestone-level planning" };
128	    }
129	    // For slice planning, try to read the context/research to gauge complexity
130	    // If research exists and is large, bump to heavy
131	    const researchPath = join(gsdRoot(basePath), mid, "slices", sid, "RESEARCH.md");
132	    try {
133	        if (existsSync(researchPath)) {
134	            const content = readFileSync(researchPath, "utf-8");
135	            const lineCount = content.split("\n").length;
136	            if (lineCount > 200) {
137	                return { tier: "heavy", reason: `complex slice: ${lineCount}-line research` };
138	            }
139	        }
140	    }
141	    catch {
142	        // Non-fatal
143	    }
144	    return null; // Use default tier
145	}
146	/**
147	 * Extract task metadata from the task plan file on disk.
148	 */
149	function extractTaskMetadata(unitId, basePath) {
150	    const meta = {};
151	    const { milestone: mid, slice: sid, task: tid } = parseUnitId(unitId);
152	    if (!mid || !sid || !tid)
153	        return meta;
154	    const taskPlanPath = join(gsdRoot(basePath), mid, "slices", sid, "tasks", `${tid}-PLAN.md`);
155	    try {
156	        if (!existsSync(taskPlanPath))
157	            return meta;
158	        const content = readFileSync(taskPlanPath, "utf-8");
159	        const lines = content.split("\n");
160	        // Count files mentioned in "Files:" or "- Files:" lines
161	        const fileLines = lines.filter(l => /^\s*-?\s*files?\s*:/i.test(l));
162	        if (fileLines.length > 0) {
163	            // Count comma-separated or bullet-pointed files
164	            const allFiles = new Set();
165	            for (const line of fileLines) {
166	                const filesStr = line.replace(/^\s*-?\s*files?\s*:\s*/i, "");
167	                const files = filesStr.split(/[,;]/).map(f => f.trim()).filter(Boolean);
168	                files.forEach(f => allFiles.add(f));
169	            }
170	            meta.fileCount = allFiles.size;
171	        }
172	        // Check for "new file" or "create" keywords
173	        meta.isNewFile = lines.some(l => /\b(create|new file|scaffold|bootstrap)\b/i.test(l));
174	        // Look for tags/labels in frontmatter or content
175	        const tags = [];
176	        if (content.match(/\b(refactor|migration|architect)/i))
177	            tags.push("refactor");
178	        if (content.match(/\b(test|spec|coverage)\b/i))
179	            tags.push("test");
180	        if (content.match(/\b(doc|readme|comment|jsdoc)\b/i))
181	            tags.push("docs");
182	        if (content.match(/\b(config|env|setting)\b/i))
183	            tags.push("config");
184	        if (content.match(/\b(rename|typo|spelling)\b/i))
185	            tags.push("rename");
186	        meta.tags = tags;
187	        // Try to extract estimated lines from content
188	        const estimateMatch = content.match(/~?\s*(\d+)\s*lines?\b/i);
189	        if (estimateMatch) {
190	            meta.estimatedLines = parseInt(estimateMatch[1], 10);
191	        }
192	        // Phase 4: Deeper introspection signals
193	        // Count fenced code blocks (```) — more code blocks = more complex implementation
194	        const codeBlockMatches = content.match(/^```/gm);
195	        meta.codeBlockCount = codeBlockMatches ? Math.floor(codeBlockMatches.length / 2) : 0;
196	        // Detect complexity keywords that suggest harder tasks
197	        const complexityKeywords = [];
