2	// Maps complexity tiers to models, enforcing downgrade-only semantics.
3	// The user's configured model is always the ceiling.
4	
5	import type { ComplexityTier, ClassificationResult } from "./complexity-classifier.js";
6	import { tierOrdinal } from "./complexity-classifier.js";
