1	/**
2	 * Model selection and dynamic routing for auto-mode unit dispatch.
3	 * Handles complexity-based routing, model resolution across providers,
4	 * and fallback chains.
5	 */
6	
7	import type { ExtensionAPI, ExtensionContext } from "@gsd/pi-coding-agent";
8	import type { GSDPreferences } from "./preferences.js";
9	import { resolveModelWithFallbacksForUnit, resolveDynamicRoutingConfig } from "./preferences.js";
10	import type { ComplexityTier } from "./complexity-classifier.js";
11	import { classifyUnitComplexity, tierLabel } from "./complexity-classifier.js";
12	import { resolveModelForComplexity, escalateTier } from "./model-router.js";
13	import { getLedger, getProjectTotals } from "./metrics.js";
14	import { unitPhaseLabel } from "./auto-dashboard.js";
15	
16	export interface ModelSelectionResult {
17	  /** Routing metadata for metrics recording */
18	  routing: { tier: string; modelDowngraded: boolean } | null;
19	}
20	
21	/**
22	 * Select and apply the appropriate model for a unit dispatch.
23	 * Handles: per-unit-type model preferences, dynamic complexity routing,
24	 * provider/model resolution, fallback chains, and start-model re-application.
25	 *
26	 * Returns routing metadata for metrics tracking.
27	 */
28	export async function selectAndApplyModel(
29	  ctx: ExtensionContext,
30	  pi: ExtensionAPI,
31	  unitType: string,
32	  unitId: string,
33	  basePath: string,
34	  prefs: GSDPreferences | undefined,
35	  verbose: boolean,
36	  autoModeStartModel: { provider: string; id: string } | null,
37	  retryContext?: { isRetry: boolean; previousTier?: string },
38	): Promise<ModelSelectionResult> {
39	  const modelConfig = resolveModelWithFallbacksForUnit(unitType);
40	  let routing: { tier: string; modelDowngraded: boolean } | null = null;
41	
42	  if (modelConfig) {
43	    const availableModels = ctx.modelRegistry.getAvailable();
44	
45	    // ─── Dynamic Model Routing ─────────────────────────────────────────
46	    const routingConfig = resolveDynamicRoutingConfig();
47	    let effectiveModelConfig = modelConfig;
48	    let routingTierLabel = "";
49	
50	    if (routingConfig.enabled) {
51	      let budgetPct: number | undefined;
52	      if (routingConfig.budget_pressure !== false) {
53	        const budgetCeiling = prefs?.budget_ceiling;
54	        if (budgetCeiling !== undefined && budgetCeiling > 0) {
55	          const currentLedger = getLedger();
56	          const totalCost = currentLedger ? getProjectTotals(currentLedger.units).cost : 0;
57	          budgetPct = totalCost / budgetCeiling;
58	        }
59	      }
60	
61	      const isHook = unitType.startsWith("hook/");
62	      const shouldClassify = !isHook || routingConfig.hooks !== false;
63	
64	      if (shouldClassify) {
65	        let classification = classifyUnitComplexity(unitType, unitId, basePath, budgetPct);
66	        const availableModelIds = availableModels.map(m => m.id);
67	
68	        // Escalate tier on retry when escalate_on_failure is enabled (default: true)
69	        if (
70	          retryContext?.isRetry &&
71	          retryContext.previousTier &&
72	          routingConfig.escalate_on_failure !== false
73	        ) {
74	          const escalated = escalateTier(retryContext.previousTier as ComplexityTier);
75	          if (escalated) {
76	            classification = { ...classification, tier: escalated, reason: "escalated after failure" };
77	            if (verbose) {
78	              ctx.ui.notify(
79	                `Tier escalation: ${retryContext.previousTier} → ${escalated} (retry after failure)`,
80	                "info",
81	              );
82	            }
83	          }
84	        }
85	
86	        const routingResult = resolveModelForComplexity(classification, modelConfig, routingConfig, availableModelIds);
87	
88	        if (routingResult.wasDowngraded) {
89	          effectiveModelConfig = {
90	            primary: routingResult.modelId,
91	            fallbacks: routingResult.fallbacks,
92	          };
93	          if (verbose) {
94	            ctx.ui.notify(
95	              `Dynamic routing [${tierLabel(classification.tier)}]: ${routingResult.modelId} (${classification.reason})`,
96	              "info",
97	            );
98	          }
99	        }
100	        routingTierLabel = ` [${tierLabel(classification.tier)}]`;
101	        routing = { tier: classification.tier, modelDowngraded: routingResult.wasDowngraded };
102	      }
103	    }
104	
105	    const modelsToTry = [effectiveModelConfig.primary, ...effectiveModelConfig.fallbacks];
106	
107	    for (const modelId of modelsToTry) {
108	      const model = resolveModelId(modelId, availableModels, ctx.model?.provider);
109	
110	      if (!model) {
111	        if (verbose) ctx.ui.notify(`Model ${modelId} not found, trying fallback.`, "info");
112	        continue;
113	      }
